// Controller: ReviewsController.cs
using System;
using System.Collections.Generic;
using System.Linq;
using System.Web;
using System.Web.Mvc;
using YourNamespace.Models; // replace this with your actual model namespace

namespace YourNamespace.Controllers
{
    public class ReviewsController : Controller
    {
        private ApplicationDbContext db = new ApplicationDbContext();  // replace 'ApplicationDbContext' with the name of your context class

        // GET: Reviews
        public ActionResult Index(int productId)
        {
            var reviews = db.Reviews.Where(r => r.ProductID == productId).ToList();
            
            return View(reviews);
        }
    }
